class Solution {
    public long minimumSteps(String s) {
        int left = 0, right = s.length() - 1;
        while (left < right && s.charAt(left) == '0') left++;
        while (right >= 0 && s.charAt(right) == '1') right--;
        return Math.max(left, right) + 1;
    }
}
```

